import { computed, unref, type ComputedRef, type MaybeRef } from "vue";
import type {
  ContentPart,
  ContentPartType,
  ButtonData,
  CardData,
  LocationData,
  AudioData,
  TracingData,
} from "../types";

type MatchCandidate = {
  type: ContentPartType;
  match: RegExpMatchArray | null;
  index: number;
};

type ValidMatch = MatchCandidate & { match: RegExpMatchArray };

/**
 * Composable for parsing Orca content markers
 * Supports both reactive and non-reactive values for streaming compatibility
 */
export function useContentParser(
  description: MaybeRef<string>
): ComputedRef<ContentPart[]> {
  return computed<ContentPart[]>(() => {
    // Support both reactive and non-reactive values
    // unref handles both refs, computed refs, and plain values
    const content = unref(description);
    const parts: ContentPart[] = [];
    let remainingContent = content || "";

    while (remainingContent.length > 0) {
      // Find all possible matches
      const matches = findMatches(remainingContent);

      if (matches.length === 0) {
        const cleanText = remainingContent.replace(/\[orca\..*?\]/g, "").trim();
        if (cleanText) {
          parts.push({ type: "text", content: cleanText });
        }
        break;
      }

      // Get first match
      const firstMatch = matches.reduce((prev, current) =>
        prev.index < current.index ? prev : current
      );

      // Add text before match
      const textBefore = remainingContent.substring(0, firstMatch.index);
      const cleanTextBefore = textBefore.replace(/\[orca\..*?\]/g, "").trim();
      if (cleanTextBefore) {
        parts.push({ type: "text", content: cleanTextBefore });
      }

      // Process match
      const matchPayloadRaw = firstMatch.match[1] ?? "";
      const matchPayload = matchPayloadRaw.trim();

      const part = processMatch(firstMatch.type, matchPayload);
      if (part) {
        parts.push(part);
      }

      // Remove processed content
      const matchEnd = firstMatch.index + firstMatch.match[0].length;
      remainingContent = remainingContent.substring(matchEnd);
    }

    return parts;
  });
}

/**
 * Find all matches in content
 */
function findMatches(content: string): ValidMatch[] {
  const patterns = [
    {
      type: "general-loading" as const,
      regex: /\[orca\.loading\.start\](.*?)\[orca\.loading\.end\]/s,
    },
    {
      type: "thinking-loading" as const,
      regex:
        /\[orca\.loading\.thinking\.start\](.*?)\[orca\.loading\.thinking\.end\]/s,
    },
    {
      type: "searching-loading" as const,
      regex:
        /\[orca\.loading\.searching\.start\](.*?)\[orca\.loading\.searching\.end\]/s,
    },
    {
      type: "coding-loading" as const,
      regex:
        /\[orca\.loading\.coding\.start\](.*?)\[orca\.loading\.coding\.end\]/s,
    },
    {
      type: "analyzing-loading" as const,
      regex:
        /\[orca\.loading\.analyzing\.start\](.*?)\[orca\.loading\.analyzing\.end\]/s,
    },
    {
      type: "generating-loading" as const,
      regex:
        /\[orca\.loading\.generating\.start\](.*?)\[orca\.loading\.generating\.end\]/s,
    },
    {
      type: "custom-loading" as const,
      regex:
        /\[orca\.loading\.custom\.start\](.*?)\[orca\.loading\.custom\.end\]/s,
    },
    {
      type: "image-loading" as const,
      regex:
        /\[orca\.(?:image\.loading|loading\.image)\.start\](.*?)\[orca\.(?:image\.loading|loading\.image)\.end\]/s,
    },
    {
      type: "video-loading" as const,
      regex:
        /\[orca\.loading\.video\.start\](.*?)\[orca\.loading\.video\.end\]/s,
    },
    {
      type: "youtube-loading" as const,
      regex:
        /\[orca\.loading\.youtube\.start\](.*?)\[orca\.loading\.youtube\.end\]/s,
    },
    {
      type: "card-loading" as const,
      regex:
        /\[orca\.loading\.(?:card|card\.list)\.start\](.*?)\[orca\.loading\.(?:card|card\.list)\.end\]/s,
    },
    {
      type: "map-loading" as const,
      regex: /\[orca\.loading\.map\.start\](.*?)\[orca\.loading\.map\.end\]/s,
    },
    {
      type: "image" as const,
      regex: /\[orca\.image\.start\](.*?)\[orca\.image\.end\]/s,
    },
    {
      type: "video" as const,
      regex: /\[orca\.video\.start\](.*?)\[orca\.video\.end\]/s,
    },
    {
      type: "youtube" as const,
      regex: /\[orca\.youtube\.start\](.*?)\[orca\.youtube\.end\]/s,
    },
    {
      type: "card" as const,
      regex: /\[orca\.list\.card\.start\](.*?)\[orca\.list\.card\.end\]/s,
    },
    {
      type: "location" as const,
      regex: /\[orca\.location\.start\](.*?)\[orca\.location\.end\]/s,
    },
    {
      type: "buttons" as const,
      regex: /\[orca\.buttons\.start\](.*?)\[orca\.buttons\.end\]/s,
    },
    {
      type: "tracing" as const,
      regex: /\[orca\.tracing\.start\](.*?)\[orca\.tracing\.end\]/s,
    },
    {
      type: "audio" as const,
      regex: /\[orca\.audio\.start\](.*?)\[orca\.audio\.end\]/s,
    },
  ];

  const matches: MatchCandidate[] = patterns.map(({ type, regex }) => {
    const match = content.match(regex);
    return {
      type,
      match,
      index: match ? content.indexOf(match[0]) : Infinity,
    };
  });

  return matches.filter(
    (m): m is ValidMatch => m.match !== null && m.index !== Infinity
  );
}

/**
 * Process match and return content part
 */
function processMatch(
  type: ContentPartType,
  payload: string
): ContentPart | null {
  switch (type) {
    case "general-loading":
    case "thinking-loading":
    case "searching-loading":
    case "coding-loading":
    case "analyzing-loading":
    case "generating-loading":
    case "custom-loading":
    case "image-loading":
    case "video-loading":
    case "youtube-loading":
    case "card-loading":
    case "map-loading":
      // Loading markers with both start and end should not be displayed
      // They are automatically replaced when actual content arrives
      return null;

    case "image":
    case "video":
    case "youtube":
      return { type, content: payload };

    case "card":
      return { type, content: parseCardData(payload) };

    case "location":
      return { type, content: parseLocationData(payload) };

    case "buttons":
      return { type, content: parseButtonData(payload) };

    case "tracing":
      return { type, content: parseTracingData(payload) };

    case "audio":
      return { type, content: parseAudioData(payload) };

    default:
      return null;
  }
}

/**
 * Parse card data from YAML-like format
 */
function parseCardData(payload: string): CardData[] {
  return payload
    .split("- ")
    .map((block) => block.trim())
    .filter((block) => block)
    .map((block) => {
      const photo = block.match(/photo:\s*(.+)/)?.[1]?.trim() || "";
      const header = block.match(/header:\s*(.+)/)?.[1]?.trim() || "";
      const subheader = block.match(/subheader:\s*(.+)/)?.[1]?.trim() || "";
      return { photo, header, subheader };
    });
}

/**
 * Parse location data
 */
function parseLocationData(payload: string): LocationData {
  const [latitude, longitude] = payload.split(",").map((coord) => coord.trim());
  const parsedLatitude = parseFloat(latitude);
  const parsedLongitude = parseFloat(longitude);
  return {
    latitude: Number.isFinite(parsedLatitude) ? parsedLatitude : 0,
    longitude: Number.isFinite(parsedLongitude) ? parsedLongitude : 0,
  };
}

/**
 * Parse button data from YAML-like format
 */
function parseButtonData(payload: string): ButtonData[] {
  return payload
    .split("- ")
    .map((block) => block.trim())
    .filter((block) => block)
    .map((block) => {
      const rawType = block.match(/type:\s*(\w+)/)?.[1]?.trim();
      const type: ButtonData["type"] = rawType === "link" ? "link" : "action";
      const label = block.match(/label:\s*(.+)/)?.[1]?.trim() || "";
      const url = block.match(/url:\s*(.+)/)?.[1]?.trim() || "";
      const idMatch = block.match(/id:\s*(\d+)/);
      const id = idMatch ? parseInt(idMatch[1].trim(), 10) : undefined;
      const colorMatch = block.match(/color:\s*([^#\s][^\r\n]*[^\s]|\S+)/);
      const color = colorMatch ? colorMatch[1].trim() : undefined;
      const rowValue = block.match(/row:\s*(\d+)/)?.[1]?.trim();
      const row = rowValue ? parseInt(rowValue, 10) : undefined;

      return { type, label, url, id, color, row };
    });
}

/**
 * Parse tracing data
 */
function parseTracingData(payload: string): TracingData {
  const visibilityMatch = payload.match(/visibility:\s*(\w+)/);
  const visibility =
    (visibilityMatch?.[1]?.trim() as TracingData["visibility"]) || "all";
  const contentMatch = payload.match(
    /content:\s*(\[.*\])(?=\s*\[orca\.tracing\.end\]|$)/s
  );
  let content = contentMatch ? contentMatch[1].trim() : payload;

  if (!contentMatch) {
    const fallbackMatch = payload.match(
      /content:\s*([^]*?)(?=\s*\[orca\.tracing\.end\]|$)/s
    );
    content = fallbackMatch ? fallbackMatch[1].trim() : payload;
  }

  return {
    visibility,
    content,
    rawContent: payload,
  };
}

/**
 * Parse audio data from YAML-like format
 */
function parseAudioData(payload: string): AudioData[] {
  return payload
    .split("- ")
    .map((block) => block.trim())
    .filter((block) => block)
    .map((block) => {
      const label = block.match(/label:\s*(.+)/)?.[1]?.trim() || "";
      const url = block.match(/url:\s*(.+)/)?.[1]?.trim() || "";
      const type = block.match(/type:\s*(.+)/)?.[1]?.trim() || "audio/mpeg";
      return { label, url, type };
    });
}
